public class MyBenefitCasesPodLoader extends PodLoader {
  @SuppressWarnings("restriction")
  @Inject
  protected BIHelper biHelper;
  /**
   * Constructor for the class.
   */
  public MyBenefitCasesPodLoader() {
    GuiceWrapper.getInjector().injectMembers(this);
  }
  // ___________________________________________________________________________
  /**
   * Load the Benefit Case Summary pod.
   *
   * The benefit case summary pod displays a POD which contains a chart. The
   * chart provides the current user with a summary of the Benefit Cases broken
   * out by the number of diagnosis.
   *
   * @param pageDocument
   *          a DOM document describing the page to be rendered.
   *
   */
  @Override
  public Node createPod(final Document workspaceDocument,
      final Map<String, Object> contexts) {
    try {
      final PodBuilder pod = PodBuilder.newPod(workspaceDocument,
          PODTYPE.SICKNESSPOD);
      // read the pod title from code table entity
      pod.setTitle(CodeTable.getOneItem(PODTYPE.TABLENAME, PODTYPE.SICKNESSPOD));
      pod.setTextResource(SPMAnalyticsConst.kBenefitPodProperties);
      // Create a BorderLayout element with a North and Center component
      final BorderLayoutBuilder borderLayout = BorderLayoutBuilder
          .newInstance(workspaceDocument);
      final Node centerComponentElement = borderLayout
          .addComponent(BorderLayoutBuilder.Constraint.Center);
